const state = items[0].json;
const iteration = Number(state.iteration || 0);
const maxIterations = Number(state.max_iterations || 24);
const nextIteration = iteration + 1;
const phases = [
  {
    key: 'index0-photo-pass',
    level: 'Index0_Game',
    title: 'INDEX-0 architectural photo-reference pass',
    goal: 'Continue rebuilding Index0_Game toward the provided industrial concrete reference: wet floor readability, red emergency accents, wall warning text, ceiling light language, pipes, panels, benches, and player-scale composition.'
  },
  {
    key: 'index1-anchor-dressing',
    level: 'Index1_Game',
    title: 'INDEX-1 anchored dressing and traversal pass',
    goal: 'Use IDX1_ROUTE_* and IDX1_EVT_* anchors as the spatial contract. Add durable lighting, audio, blocking, trigger placement, checkpoint planning, and visual dressing around the anchors without anonymous coordinate sprawl.'
  },
  {
    key: 'index2-chamber-polish',
    level: 'Index2_Game',
    title: 'INDEX-2 chamber continuity and atmosphere pass',
    goal: 'Strengthen INDEX-5 chamber continuity, readable transitions, co-op interaction staging, scare timing, and end-route clarity while preserving existing C++ controller contracts.'
  },
  {
    key: 'shared-systems-hardening',
    level: 'ProjectWide',
    title: 'Shared MercyHF systems hardening pass',
    goal: 'Improve reusable structure across docs, tags, Blueprint conventions, level transition contracts, and agent handoff rules. Avoid broad rewrites; make changes that future passes can build on safely.'
  }
];
const phase = phases[iteration % phases.length];
const title = `${phase.title} - loop ${nextIteration}/${maxIterations}`;
const body = `### Autonomous Loop
Loop ID: ${state.loop_id}\nIteration: ${nextIteration}/${maxIterations}\nMode: ${state.mode}\nTarget agent: ${state.target_agent}\nLevel focus: ${phase.level}\n\n### Strategic Goal\n${phase.goal}\n\n### Previous Context\n${state.last_result_summary}\n\n### Operating Rules\n- Build correctly and durably; think several passes ahead.\n- Read AGENTS.md and CLAUDE.md before touching the project.\n- Preserve existing Codex/user/other-agent changes. Do not revert unrelated dirty files.\n- Prefer existing MercyHF C++ controllers and tags over one-off Blueprint/script logic.\n- For Index1_Game, attach new systems to IDX1_ROUTE_* and IDX1_EVT_* anchors.\n- For wall text, set explicit Unreal Rotator fields and keep text aligned to wall planes.\n- Do not claim a clean C++ build if UBT is blocked by Live Coding or an open editor.\n- Report exact changed files and the next architectural task to feed back into this loop.\n\n### Output Contract\nReturn a concise implementation report with:\n1. changed files;\n2. map/assets touched;\n3. important design decisions;\n4. next recommended loop task;\n5. any blocker requiring human decision.\n\n### Continue Rule\nAt the end, call the loop webhook again with updated last_result_summary if there is no human blocker. Keep the loop focused on architectural forward progress, not random expansion.`;
return [{ json: {
  ...state,
  next_iteration: nextIteration,
  continue_loop: Boolean(state.loop_enabled) && nextIteration < maxIterations,
  phase_key: phase.key,
  task_title: title,
  task_description: body,
  task_type: 'autonomous-loop',
  priority: 'high',
  level: phase.level,
  next_payload: {
    loop_id: state.loop_id,
    target_agent: state.target_agent,
    level_focus: state.level_focus,
    mode: state.mode,
    iteration: nextIteration,
    max_iterations: maxIterations,
    delay_seconds: Number(state.delay_seconds || 900),
    loop_enabled: Boolean(state.loop_enabled),
    repository_owner: state.repository_owner,
    repository_name: state.repository_name,
    webhook_base_url: state.webhook_base_url,
    last_result_summary: `Previous issue created: ${title}. Continue with the next architectural phase unless a human blocker was reported.`
  }
}}];
